import pytest

def test_wire_transfer_boundary_100000_requires_manual_review(
    api_client, fresh_2fa_token, high_balance_account
):
    headers = {
        "Authorization": f"Bearer {high_balance_account['token']}",
        "X-2FA-Token": fresh_2fa_token,
    }
    payload = {
        "from_account": high_balance_account["account_id"],
        "to_routing": "<routing_number>",
        "to_account": "<beneficiary_account>",
        "amount": 100000,
        "currency": "USD",
    }
    resp = api_client.post("/transfers/wire", json=payload, headers=headers)
    assert resp.status_code == 202
    body = resp.json()
    status = body.get("status", "").lower()
    assert "manual" in status or "review" in status

import pytest

def test_wire_transfer_insufficient_funds_rejected(
    api_client, fresh_2fa_token, low_balance_account
):
    headers = {
        "Authorization": f"Bearer {low_balance_account['token']}",
        "X-2FA-Token": fresh_2fa_token,
    }
    payload = {
        "from_account": low_balance_account["account_id"],
        "to_routing": "<routing_number>",
        "to_account": "<beneficiary_account>",
        "amount": 5000,
        "currency": "USD",
    }
    resp = api_client.post("/transfers/wire", json=payload, headers=headers)
    assert resp.status_code in (400, 422)
    body = resp.json()
    error = body.get("error", "").lower()
    assert any(kw in error for kw in ("insufficient", "funds", "balance"))
